115→type HeaderComponentProps = {
116→  isCartVisible?: boolean
117→  cartItems?: CartItem[]
118→  totalPrice?: number
119→  logoOnly?: boolean
120→  sticky?: boolean
121→  toggleCartVisibility?: () => void
122→  goToCheckout?: () => void
123→  saveItem?: (item: CartItem) => void
124→}
125→
126→export const HeaderComponent = ({
127→  isCartVisible = false,
128→  logoOnly = false,
129→  sticky = false,
130→  totalPrice = 0,
131→  cartItems = [],
132→  toggleCartVisibility = () => {},
133→  goToCheckout = () => {},
134→  saveItem = () => {},
135→}: HeaderComponentProps) => (
136→  <HeaderContainer data-testid="header" $sticky={sticky}>
137→    <LogoContainer to="/" aria-label="go to home page">
138→      <Logo />
139→    </LogoContainer>
140→    {!logoOnly && (
141→      <>
142→        <OptionsContainer>
143→          <span className="navigation-items">
144→            <ThemeToggle />
145→            <Link to="/" tabIndex={-1}>
146→              <Button clear>Home</Button>
147→            </Link>
148→            <Link to="/categories" tabIndex={-1}>
149→              <Button clear>All restaurants</Button>
150→            </Link>
151→          </span>
152→          <Button aria-label="food cart" icon="cart" onClick={toggleCartVisibility}>
153→            {totalPrice > 0 && (
154→              <>
155→                <CartText type="span">Order</CartText>
156→                <CartTotal type="span">{toCurrency(totalPrice)}</CartTotal>
157→              </>
158→            )}
159→          </Button>
160→        </OptionsContainer>
161→        <ShoppingCartMenu
162→          isOpen={isCartVisible}
163→          onClose={toggleCartVisibility}
164→          onGoToCheckoutClick={goToCheckout}
165→          cartItems={cartItems}
166→          totalPrice={totalPrice}
167→          onItemChange={saveItem}
168→        />
169→      </>
170→    )}
171→  </HeaderContainer>
172→)
173→
174→export const Header = ({ sticky }: { sticky?: boolean }) => {
175→  const isCartVisible = useAppSelector(selectCartVisibility)
176→  const cartItems = useAppSelector(selectCartItems)
177→  const totalPrice = useAppSelector(selectCartTotal)
178→  const dispatch = useAppDispatch()
179→  const navigate = useNavigate()
180→  const toggleCartVisibility = () => dispatch(toggleVisibilityAction())
181→  const saveItem = (item: CartItem) => dispatch(saveItemAction(item))
182→
183→  const goToCheckout = () => {
184→    toggleCartVisibility()
185→    navigate('/checkout')
186→  }
187→
188→  return (
189→    <HeaderComponent
190→      sticky={sticky}
191→      goToCheckout={goToCheckout}
192→      cartItems={cartItems}
193→      isCartVisible={isCartVisible}
194→      toggleCartVisibility={toggleCartVisibility}
195→      totalPrice={totalPrice}
196→      saveItem={saveItem}
197→    />
198→  )
199→}
