import { Link } from 'react-router-dom'
import styled, { css } from 'styled-components'

import { Body } from '../typography/Body'
import { Heading } from '../typography/Heading'

const FooterCardContainer = styled.div(
  ({
    theme: {
      color: colors,
      spacing,
      borderRadius,
      typography: { fontSize },
    },
  }) => css`
    color: ${colors.white};

    border-radius: ${borderRadius.xs};
    h2 {
      color: white;
      margin-bottom: ${spacing.xs};
      font-size: ${fontSize.heading4};
    }

    ul {
      list-style: none;
      margin: 0;
      padding: 0;
    }

    a {
      color: ${colors.white};
      text-decoration: none;
      cursor: pointer;
    }

    p {
      margin-top: ${spacing.xs};
      margin-bottom: ${spacing.xs};
    }
  `
)

type FooterCardProps = {
  title: string
  links?: {
    external?: boolean
    name: string
    href: string
  }[]
}

export const FooterCard: React.FC<React.PropsWithChildren<FooterCardProps>> = ({
  title,
  links = [],
  children,
}) => (
  <FooterCardContainer>
    <Heading level={2}>{title}</Heading>
    {links.length > 0 && (
      <ul>
        {links.map(({ external, name, href }) => (
          <li key={name}>
            <Body>
              {external ? (
                <a target="_blank" rel="noopener noreferrer" href={href}>
                  {name}
                </a>
              ) : (
                <Link to={href}>{name}</Link>
              )}
            </Body>
          </li>
        ))}
      </ul>
    )}
    {children}
  </FooterCardContainer>
)

import styled, { useTheme } from 'styled-components'

const StyledSVG = styled.svg`
  display: block;
`

export type IconName =
  | 'arrow-right'
  | 'arrow-left'
  | 'cross'
  | 'cart'
  | 'minus'
  | 'plus'
  | 'moon'
  | 'sun'
  | 'star'

type IconProps = {
  name: IconName
  color?: string
  size?: number | string
}

export const Icon = ({ name, color, size = '1.5rem' }: IconProps) => {
  const { color: themeColor } = useTheme()
  return (
    <StyledSVG
      stroke={color || themeColor.primaryText}
      width={size}
      height={size}
      style={{ minWidth: size }}
    >
      <use xlinkHref={`/sprite-map.svg#${name}`} />
    </StyledSVG>
  )
}

